sql:
SELECT COUNT(*) as num_of_interactions 
FROM protein_interactions 
WHERE interaction_type = 'binding' AND score > 0.9;

SELECT protein_name
FROM proteins
WHERE molecular_weight > (SELECT AVG(molecular_weight) FROM proteins);

SELECT protein_name, source
FROM proteins
WHERE molecular_weight > (SELECT AVG(molecular_weight) FROM proteins);

SELECT AVG(molecular_weight) 
FROM proteins 
WHERE length > 5000 AND isoelectric_point > 7;

external_knowledge:
- Protein identities and enzymatic codes refer to the protein names and EC numbers;
- The tally of scientific papers is a count of the number of publications associated with each protein;
- The term 'identities' is used here to refer to the unique names of the proteins to maintain a vague style.

- 'Notable domains' refers to features in proteins classified as 'domain'.;
- 'Engaged in some kind of interaction' means the protein is listed in the interaction data as interacting with another protein (second protein in the interaction).;
- The term 'engaged' is used metaphorically to imply the protein is part of an interaction pair.;

sql:
SELECT COUNT(*) AS num_proteins
FROM proteins
WHERE source = 'experimental' AND length > (
  SELECT AVG(molecular_weight)
  FROM proteins
);

SELECT COUNT(*) AS number_of_proteins
FROM proteins
WHERE molecular_weight > (SELECT AVG(molecular_weight) FROM proteins);

SELECT AVG(p.molecular_weight) AS average_molecular_weight
FROM proteins p
WHERE p.protein_id IN (SELECT DISTINCT e.protein_id FROM experiments e);

SELECT protein_name, length
FROM proteins
WHERE length = (SELECT MAX(length) FROM proteins);

SELECT e.experiment_id, MAX(e.protein_id) AS highest_protein_id
FROM experiments e
GROUP BY e.experiment_id;

SELECT AVG(length) AS average_length
FROM proteins
WHERE source = 'experimental';
